package main

import (
	"errors"
	"fmt"
	"sync"
)

var (
	ErrAccountNotFound   = errors.New("account not found")
	ErrInsufficientFunds = errors.New("insufficient funds")
	ErrNegativeAmount    = errors.New("amount must be positive")
)

type Bank struct {
	mu       sync.RWMutex
	accounts map[string]float64
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]float64),
	}
}

func (b *Bank) CreateAccount(id string, initialBalance float64) error {
	if initialBalance < 0 {
		return ErrNegativeAmount
	}
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[id] = initialBalance
	return nil
}

func (b *Bank) GetBalance(id string) (float64, error) {
	b.mu.RLock()
	defer b.mu.RUnlock()
	balance, ok := b.accounts[id]
	if !ok {
		return 0, ErrAccountNotFound
	}
	return balance, nil
}

// Deposit atomically adds amount to the account balance.
// The check for account existence and the update happen under the same lock.
func (b *Bank) Deposit(id string, amount float64) (float64, error) {
	if amount <= 0 {
		return 0, ErrNegativeAmount
	}
	b.mu.Lock()
	defer b.mu.Unlock()
	balance, ok := b.accounts[id]
	if !ok {
		return 0, ErrAccountNotFound
	}
	newBalance := balance + amount
	b.accounts[id] = newBalance
	return newBalance, nil
}

// Withdraw atomically subtracts amount from the account balance.
// The balance check and update are performed under the same write lock
// to prevent TOCTOU race conditions where two concurrent withdrawals
// could both see sufficient funds and overdraw the account.
func (b *Bank) Withdraw(id string, amount float64) (float64, error) {
	if amount <= 0 {
		return 0, ErrNegativeAmount
	}
	b.mu.Lock()
	defer b.mu.Unlock()
	balance, ok := b.accounts[id]
	if !ok {
		return 0, ErrAccountNotFound
	}
	if balance < amount {
		return balance, ErrInsufficientFunds
	}
	newBalance := balance - amount
	b.accounts[id] = newBalance
	return newBalance, nil
}

// Transfer atomically moves funds from one account to another.
// Both the source balance check and both account updates happen
// under a single lock acquisition to prevent race conditions.
func (b *Bank) Transfer(fromID, toID string, amount float64) error {
	if amount <= 0 {
		return ErrNegativeAmount
	}
	b.mu.Lock()
	defer b.mu.Unlock()

	fromBalance, ok := b.accounts[fromID]
	if !ok {
		return fmt.Errorf("source %s: %w", fromID, ErrAccountNotFound)
	}
	_, ok = b.accounts[toID]
	if !ok {
		return fmt.Errorf("destination %s: %w", toID, ErrAccountNotFound)
	}
	if fromBalance < amount {
		return ErrInsufficientFunds
	}
	b.accounts[fromID] -= amount
	b.accounts[toID] += amount
	return nil
}

func main() {
	bank := NewBank()

	bank.CreateAccount("alice", 1000.0)
	bank.CreateAccount("bob", 500.0)
	bank.CreateAccount("charlie", 250.0)

	var wg sync.WaitGroup
	numWorkers := 100

	// Concurrent deposits
	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			_, err := bank.Deposit("alice", 10.0)
			if err != nil {
				fmt.Printf("Deposit error: %v\n", err)
			}
		}()
	}

	// Concurrent withdrawals — some may fail with insufficient funds, which is correct
	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			_, err := bank.Withdraw("bob", 5.0)
			if err != nil && !errors.Is(err, ErrInsufficientFunds) {
				fmt.Printf("Withdraw error: %v\n", err)
			}
		}()
	}

	// Concurrent transfers
	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			err := bank.Transfer("alice", "charlie", 1.0)
			if err != nil && !errors.Is(err, ErrInsufficientFunds) {
				fmt.Printf("Transfer error: %v\n", err)
			}
		}()
	}

	// Concurrent balance reads
	for i := 0; i < numWorkers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			_, _ = bank.GetBalance("alice")
			_, _ = bank.GetBalance("bob")
			_, _ = bank.GetBalance("charlie")
		}()
	}

	wg.Wait()

	// Print final balances
	for _, id := range []string{"alice", "bob", "charlie"} {
		bal, _ := bank.GetBalance(id)
		fmt.Printf("Account %s: $%.2f\n", id, bal)
	}

	// Verify conservation of money
	aliceBal, _ := bank.GetBalance("alice")
	bobBal, _ := bank.GetBalance("bob")
	charlieBal, _ := bank.GetBalance("charlie")
	total := aliceBal + bobBal + charlieBal
	fmt.Printf("Total money in system: $%.2f\n", total)
	// Initial: 1000 + 500 + 250 = 1750
	// Deposits: +1000 (100 * 10)
	// Withdrawals: up to -500 (100 * 5, but bob only had 500)
	// Transfers: move money between accounts (no net change)
	fmt.Println("(Initial total was $1750.00, plus $1000.00 in deposits, minus withdrawals from Bob)")
}